
#include "svg_helper.h"
int main(){string stem="11_iterative_merge_sort",title="11 Iterative Merge Sort"; vector<vector<int>> frames={{5,3,8,1,4,7},{3,5,1,8,4,7},{1,3,5,8,4,7},{1,3,4,5,7,8},{1,3,4,5,7,8}}; vector<int> width={1,2,4,8,8}; vector<string> f={"bottom-up, no recursion","merge runs of size 1,2,4...","temporary array collects output","whole array sorted after final pass"}; for(int k=0;k<frames.size();++k){int W=1140,H=680; string s=startSVG(W,H,title,"Step "+to_string(k+1)+" / "+to_string(frames.size())+" - bottom-up merge run width = "+to_string(width[k])); s+=box(50,120,610,400,"#fff","#bfd3e6"); s+=T(90,155,"Iterative merge sort: merge adjacent runs by increasing width",17,"#123","700"); s+=arr(frames[k],90,190,{}, k>=3?set<int>{0,1,2,3,4,5}:set<int>{}); for(int i=0;i<6;i+=max(1,width[k])){int ww=min(width[k],6-i)*58; s+=box(90+i*58,275,ww,45,(i/width[k])%2?"#fef3c7":"#dbeafe","#64748b"); s+=T(90+i*58+8,305,"run",14,"#334155","700");} s+=arrow(250,345,250,420,"#d92d27",4); s+=box(90,430,350,58,"#eefdf3","#16a34a")+T(115,465,"merged output buffer",16,"#166534","700"); s+=sidebar(k+1,frames.size(),f)+footer(W,H,stem+".cpp"); stringstream p; p<<"output/"<<stem<<"_steps/step_"<<setw(2)<<setfill('0')<<k+1<<".svg"; writeFile(p.str(),s+endSVG());}}
